return 0;

static async Task<IScheduler> BuildScheduler(string schedulerName, string connectionString)
{
    var config = SchedulerBuilder.Create("AUTO", schedulerName);
    config.UseDefaultThreadPool(x => x.MaxConcurrency = 1);
    config.UsePersistentStore(store =>
    {
        store.UseProperties = false;
        store.PerformSchemaValidation = true;
        store.UseGenericDatabase("SQLite-Microsoft", "server-01", db => db.ConnectionString = connectionString);
        store.UseSystemTextJsonSerializer(j => j.AddTriggerSerializer<CustomTrigger>(new CustomTriggerSerializer()));
    });

    return await config.BuildScheduler();
}

static async Task RemoveFireTimesFromBlobAndSetPrevious(string connectionString, TriggerKey triggerKey, DateTimeOffset previousFireTime)
{
    await using var connection = new SqliteConnection(connectionString);
    await connection.OpenAsync();

    byte[] blob;
    await using (var select = connection.CreateCommand())
    {
        select.CommandText = "SELECT BLOB_DATA FROM QRTZ_BLOB_TRIGGERS WHERE TRIGGER_NAME = $name AND TRIGGER_GROUP = $group";
        select.Parameters.AddWithValue("$name", triggerKey.Name);
        select.Parameters.AddWithValue("$group", triggerKey.Group);
        blob = (byte[]) (await select.ExecuteScalarAsync() ?? throw new InvalidOperationException("Missing blob trigger row."));
    }

    using var document = JsonDocument.Parse(blob);
    await using var stream = new MemoryStream();
    await using (var writer = new Utf8JsonWriter(stream))
    {
        writer.WriteStartObject();
        foreach (var property in document.RootElement.EnumerateObject())
        {
            if (property.NameEquals("NextFireTimeUtc") || property.NameEquals("PreviousFireTimeUtc"))
            {
                continue;
            }
            property.WriteTo(writer);
        }
        writer.WriteEndObject();
    }

    await using (var updateBlob = connection.CreateCommand())
    {
        updateBlob.CommandText = "UPDATE QRTZ_BLOB_TRIGGERS SET BLOB_DATA = $blob WHERE TRIGGER_NAME = $name AND TRIGGER_GROUP = $group";
        updateBlob.Parameters.AddWithValue("$blob", stream.ToArray());
        updateBlob.Parameters.AddWithValue("$name", triggerKey.Name);
        updateBlob.Parameters.AddWithValue("$group", triggerKey.Group);
        await updateBlob.ExecuteNonQueryAsync();
    }

    await using (var updateTrigger = connection.CreateCommand())
    {
        updateTrigger.CommandText = "UPDATE QRTZ_TRIGGERS SET PREV_FIRE_TIME = $previous WHERE TRIGGER_NAME = $name AND TRIGGER_GROUP = $group";
        updateTrigger.Parameters.AddWithValue("$previous", previousFireTime.UtcTicks);
        updateTrigger.Parameters.AddWithValue("$name", triggerKey.Name);
        updateTrigger.Parameters.AddWithValue("$group", triggerKey.Group);
        await updateTrigger.ExecuteNonQueryAsync();
    }
}

[Serializable]
internal sealed class CustomTrigger : CronTriggerImpl
{
    public override bool HasAdditionalProperties => true;
}

internal sealed class CustomTriggerSerializer : CronTriggerSerializer
{
    public override string TriggerTypeForJson => "CustomTrigger";

    public override IScheduleBuilder CreateScheduleBuilder(JsonElement jsonElement, JsonSerializerOptions options)
    {
        var cronExpressionString = jsonElement.GetProperty(options.GetPropertyName("CronExpressionString")).GetString()!;
        var timeZone = jsonElement.GetProperty(options.GetPropertyName("TimeZone")).GetTimeZone();
        return CronScheduleBuilder.CronSchedule(cronExpressionString).InTimeZone(timeZone).BuildCustomTrigger();
    }

    private sealed class CustomTriggerScheduleBuilder : ScheduleBuilder<CustomTrigger>
    {
        public override IMutableTrigger Build() => new CustomTrigger();
    }
}

internal static class CustomTriggerScheduleBuilderExtensions
{
    public static ScheduleBuilder<CustomTrigger> BuildCustomTrigger(this CronScheduleBuilder builder) => new CustomTriggerScheduleBuilder(builder);

    private sealed class CustomTriggerScheduleBuilder(CronScheduleBuilder builder) : ScheduleBuilder<CustomTrigger>
    {
        public override IMutableTrigger Build()
        {
            var source = (ICronTrigger) builder.Build();
            return new CustomTrigger
            {
                CronExpressionString = source.CronExpressionString,
                TimeZone = source.TimeZone,
                MisfireInstruction = source.MisfireInstruction
            };
        }
    }
}

internal sealed class NoOpJob : IJob
{
    public ValueTask Execute(IJobExecutionContext context) => ValueTask.CompletedTask;
}
