    }

    public static TimeSpan GetTimeSpan(this JsonElement jsonElement)
    {
        var value = jsonElement.GetString() ?? "";
        var result = TimeSpan.ParseExact(value, "c", CultureInfo.InvariantCulture);
        return result;
    }

